85: // RegistrationHandler is the handler which is fed to the pluginwatcher API.
86: type RegistrationHandler struct {
87: 	csiPlugin *csiPlugin
88: }
89: 
90: // TODO (verult) consider using a struct instead of global variables
91: // csiDrivers map keep track of all registered CSI drivers on the node and their
92: // corresponding sockets
93: var csiDrivers = &DriversStore{}
94: 
95: var nim nodeinfomanager.Interface
96: 
97: var csiNodeUpdaterVar *csiNodeUpdater
98: 
99: // PluginHandler is the plugin registration handler interface passed to the
100: // pluginwatcher module in kubelet
101: var PluginHandler = &RegistrationHandler{}
102: 
103: // ValidatePlugin is called by kubelet's plugin watcher upon detection
104: // of a new registration socket opened by CSI Driver registrar side car.
105: func (h *RegistrationHandler) ValidatePlugin(pluginName string, endpoint string, versions []string) error {
106: 	klog.Info(log("Trying to validate a new CSI Driver with name: %s endpoint: %s versions: %s",
107: 		pluginName, endpoint, strings.Join(versions, ",")))
108: 
109: 	_, err := h.validateVersions("ValidatePlugin", pluginName, endpoint, versions)
110: 	if err != nil {
111: 		return fmt.Errorf("validation failed for CSI Driver %s at endpoint %s: %v", pluginName, endpoint, err)
112: 	}
113: 
114: 	return err
115: }
116: 
117: // RegisterPlugin is called when a plugin can be registered
118: func (h *RegistrationHandler) RegisterPlugin(pluginName string, endpoint string, versions []string, pluginClientTimeout *time.Duration) error {
119: 	klog.Info(log("Register new plugin with name: %s at endpoint: %s", pluginName, endpoint))
120: 
121: 	highestSupportedVersion, err := h.validateVersions("RegisterPlugin", pluginName, endpoint, versions)
122: 	if err != nil {
123: 		return err
124: 	}
125: 
126: 	// Storing endpoint of newly registered CSI driver into the map, where CSI driver name will be the key
127: 	// all other CSI components will be able to get the actual socket of CSI drivers by its name.
128: 	csiDrivers.Set(pluginName, Driver{
129: 		endpoint:                endpoint,
130: 		highestSupportedVersion: highestSupportedVersion,
131: 	})
132: 
133: 	// Get node info from the driver.
134: 	csi, err := newCsiDriverClient(csiDriverName(pluginName))
135: 	if err != nil {
136: 		return err
137: 	}
138: 
139: 	var timeout time.Duration
140: 	if pluginClientTimeout == nil {
141: 		timeout = csiTimeout
142: 	} else {
143: 		timeout = *pluginClientTimeout
144: 	}
145: 
146: 	ctx, cancel := context.WithTimeout(context.Background(), timeout)
147: 	defer cancel()
148: 
149: 	driverNodeID, maxVolumePerNode, accessibleTopology, err := csi.NodeGetInfo(ctx)
150: 	if err != nil {
151: 		if unregErr := unregisterDriver(pluginName); unregErr != nil {
152: 			klog.Error(log("registrationHandler.RegisterPlugin failed to unregister plugin due to previous error: %v", unregErr))
153: 		}
154: 		return err
155: 	}
156: 
157: 	err = nim.InstallCSIDriver(pluginName, driverNodeID, maxVolumePerNode, accessibleTopology)
158: 	if err != nil {
159: 		if unregErr := unregisterDriver(pluginName); unregErr != nil {
160: 			klog.Error(log("registrationHandler.RegisterPlugin failed to unregister plugin due to previous error: %v", unregErr))
161: 		}
162: 		return err
163: 	}
164: 
165: 	if csiNodeUpdaterVar != nil {
166: 		csiNodeUpdaterVar.syncDriverUpdater(pluginName)
167: 	}
168: 
169: 	return nil
170: }
