172: func updateCSIDriver(pluginName string) error {
173: 	csi, err := newCsiDriverClient(csiDriverName(pluginName))
174: 	if err != nil {
175: 		return fmt.Errorf("failed to create CSI client for driver %q: %w", pluginName, err)
176: 	}
177: 
178: 	ctx, cancel := context.WithTimeout(context.Background(), csiTimeout)
179: 	defer cancel()
180: 
181: 	driverNodeID, maxVolumePerNode, accessibleTopology, err := csi.NodeGetInfo(ctx)
182: 	if err != nil {
183: 		return fmt.Errorf("failed to get NodeGetInfo from driver %q: %w", pluginName, err)
184: 	}
185: 
186: 	if err := nim.UpdateCSIDriver(pluginName, driverNodeID, maxVolumePerNode, accessibleTopology); err != nil {
187: 		return fmt.Errorf("failed to update driver %q: %w", pluginName, err)
188: 	}
189: 	return nil
190: }
