192: func (p *csiPlugin) VerifyExhaustedResource(spec *volume.Spec) bool {
193: 	if spec == nil || spec.PersistentVolume == nil || spec.PersistentVolume.Spec.CSI == nil {
194: 		klog.ErrorS(nil, "Invalid volume spec for CSI")
195: 		return false
196: 	}
197: 
198: 	pluginName := spec.PersistentVolume.Spec.CSI.Driver
199: 
200: 	driver, err := p.getCSIDriver(pluginName)
201: 	if err != nil {
202: 		klog.ErrorS(err, "Failed to retrieve CSIDriver", "pluginName", pluginName)
203: 		return false
204: 	}
205: 
206: 	period := getNodeAllocatableUpdatePeriod(driver)
207: 	if period == 0 {
208: 		return false
209: 	}
210: 
211: 	volumeHandle := spec.PersistentVolume.Spec.CSI.VolumeHandle
212: 	attachmentName := getAttachmentName(volumeHandle, pluginName, string(p.host.GetNodeName()))
213: 	kubeClient := p.host.GetKubeClient()
214: 
215: 	ctx, cancel := context.WithTimeout(context.Background(), csiTimeout)
216: 	defer cancel()
217: 
218: 	attachment, err := kubeClient.StorageV1().VolumeAttachments().Get(ctx, attachmentName, meta.GetOptions{})
219: 	if err != nil {
220: 		klog.ErrorS(err, "Failed to get volume attachment", "attachmentName", attachmentName)
221: 		return false
222: 	}
223: 
224: 	if isResourceExhaustError(attachment) {
225: 		klog.V(4).InfoS("Detected ResourceExhausted error for volume", "pluginName", pluginName, "volumeHandle", volumeHandle)
226: 		if err := updateCSIDriver(pluginName); err != nil {
227: 			klog.ErrorS(err, "Failed to update CSIDriver", "pluginName", pluginName)
228: 		}
229: 		return true
230: 	}
231: 	return false
232: }
233: 
234: func isResourceExhaustError(attachment *storage.VolumeAttachment) bool {
235: 	if attachment == nil || attachment.Status.AttachError == nil {
236: 		return false
237: 	}
238: 	return attachment.Status.AttachError.ErrorCode != nil &&
239: 		*attachment.Status.AttachError.ErrorCode == int32(codes.ResourceExhausted)
240: }
