242: func (h *RegistrationHandler) validateVersions(callerName, pluginName string, endpoint string, versions []string) (*utilversion.Version, error) {
243: 	if len(versions) == 0 {
244: 		return nil, errors.New(log("%s for CSI driver %q failed. Plugin returned an empty list for supported versions", callerName, pluginName))
245: 	}
246: 
247: 	// Validate version
248: 	// CSI currently only has version 0.x and 1.x (see https://github.com/container-storage-interface/spec/releases).
249: 	// Therefore any driver claiming version 2.x+ is ignored as an unsupported versions.
250: 	// Future 1.x versions of CSI are supposed to be backwards compatible so this version of Kubernetes will work with any 1.x driver
251: 	// (or 0.x), but it may not work with 2.x drivers (because 2.x does not have to be backwards compatible with 1.x).
252: 	// CSI v0.x is no longer supported as of Kubernetes v1.17 in accordance with deprecation policy set out in Kubernetes v1.13.
253: 	newDriverHighestVersion, err := utilversion.HighestSupportedVersion(versions)
254: 	if err != nil {
255: 		return nil, errors.New(log("%s for CSI driver %q failed. None of the versions specified %q are supported. err=%v", callerName, pluginName, versions, err))
256: 	}
257: 
258: 	existingDriver, driverExists := csiDrivers.Get(pluginName)
259: 	if driverExists {
260: 		if !existingDriver.highestSupportedVersion.LessThan(newDriverHighestVersion) {
261: 			return nil, errors.New(log("%s for CSI driver %q failed. Another driver with the same name is already registered with a higher supported version: %q", callerName, pluginName, existingDriver.highestSupportedVersion))
262: 		}
263: 	}
264: 
265: 	return newDriverHighestVersion, nil
266: }
