268: // DeRegisterPlugin is called when a plugin removed its socket, signaling
269: // it is no longer available
270: func (h *RegistrationHandler) DeRegisterPlugin(pluginName, endpoint string) {
271: 	klog.Info(log("registrationHandler.DeRegisterPlugin request for plugin %s, endpoint %s", pluginName, endpoint))
272: 	if err := unregisterDriver(pluginName); err != nil {
273: 		klog.Error(log("registrationHandler.DeRegisterPlugin failed: %v", err))
274: 	}
275: 
276: 	if csiNodeUpdaterVar != nil {
277: 		csiNodeUpdaterVar.syncDriverUpdater(pluginName)
278: 	}
279: }
