281: func (p *csiPlugin) Init(host volume.VolumeHost) error {
282: 	p.host = host
283: 
284: 	csiClient := host.GetKubeClient()
285: 	if csiClient == nil {
286: 		klog.Warning(log("kubeclient not set, assuming standalone kubelet"))
287: 	} else {
288: 		// set CSIDriverLister and volumeAttachmentLister
289: 		seLinuxHost, ok := host.(volume.CSIDriverVolumeHost)
290: 		if ok {
291: 			p.csiDriverLister = seLinuxHost.CSIDriverLister()
292: 			if p.csiDriverLister == nil {
293: 				klog.Error(log("CSIDriverLister not found on CSIDriverVolumeHost"))
294: 			}
295: 		}
296: 		adcHost, ok := host.(volume.AttachDetachVolumeHost)
297: 		if ok {
298: 			p.volumeAttachmentLister = adcHost.VolumeAttachmentLister()
299: 			if p.volumeAttachmentLister == nil {
300: 				klog.Error(log("VolumeAttachmentLister not found on AttachDetachVolumeHost"))
301: 			}
302: 		}
303: 		kletHost, ok := host.(volume.KubeletVolumeHost)
304: 		if ok {
305: 			p.csiDriverLister = kletHost.CSIDriverLister()
306: 			if p.csiDriverLister == nil {
307: 				klog.Error(log("CSIDriverLister not found on KubeletVolumeHost"))
308: 			}
309: 			p.serviceAccountTokenGetter = host.GetServiceAccountTokenFunc()
310: 			if p.serviceAccountTokenGetter == nil {
311: 				klog.Error(log("ServiceAccountTokenGetter not found on KubeletVolumeHost"))
312: 			}
313: 			// We don't run the volumeAttachmentLister in the kubelet context
314: 			p.volumeAttachmentLister = nil
315: 
316: 			informerFactory := kletHost.GetInformerFactory()
317: 			if informerFactory == nil {
318: 				klog.Error(log("InformerFactory not found on KubeletVolumeHost"))
319: 			} else {
320: 				p.csiDriverInformer = informerFactory.Storage().V1().CSIDrivers().Informer()
321: 			}
322: 		}
323: 	}
324: 
325: 	var migratedPlugins = map[string](func() bool){
326: 		csitranslationplugins.GCEPDInTreePluginName: func() bool {
327: 			return true
328: 		},
329: 		csitranslationplugins.AWSEBSInTreePluginName: func() bool {
330: 			return true
331: 		},
332: 		csitranslationplugins.CinderInTreePluginName: func() bool {
333: 			return true
334: 		},
335: 		csitranslationplugins.AzureDiskInTreePluginName: func() bool {
336: 			return true
337: 		},
338: 		csitranslationplugins.AzureFileInTreePluginName: func() bool {
339: 			return true
340: 		},
341: 		csitranslationplugins.VSphereInTreePluginName: func() bool {
342: 			return true
343: 		},
344: 		csitranslationplugins.PortworxVolumePluginName: func() bool {
345: 			return true
346: 		},
347: 	}
348: 
349: 	// Initializing the label management channels
350: 	nim = nodeinfomanager.NewNodeInfoManager(host.GetNodeName(), host, migratedPlugins)
351: 	PluginHandler.csiPlugin = p
352: 
353: 	// This function prevents Kubelet from posting Ready status until CSINode
354: 	// is both installed and initialized
355: 	if err := initializeCSINode(host, p.csiDriverInformer); err != nil {
356: 		return errors.New(log("failed to initialize CSINode: %v", err))
357: 	}
358: 	return nil
359: }
