361: func initializeCSINode(host volume.VolumeHost, csiDriverInformer cache.SharedIndexInformer) error {
362: 	kvh, ok := host.(volume.KubeletVolumeHost)
363: 	if !ok {
364: 		klog.V(4).Info("Cast from VolumeHost to KubeletVolumeHost failed. Skipping CSINode initialization, not running on kubelet")
365: 		return nil
366: 	}
367: 	kubeClient := host.GetKubeClient()
368: 	if kubeClient == nil {
369: 		// Kubelet running in standalone mode. Skip CSINode initialization
370: 		klog.Warning("Skipping CSINode initialization, kubelet running in standalone mode")
371: 		return nil
372: 	}
373: 
374: 	kvh.SetKubeletError(errors.New("CSINode is not yet initialized"))
375: 
376: 	go func() {
377: 		defer utilruntime.HandleCrash()
378: 
379: 		// First wait indefinitely to talk to Kube APIServer
380: 		nodeName := host.GetNodeName()
381: 		err := waitForAPIServerForever(kubeClient, nodeName)
382: 		if err != nil {
383: 			klog.Fatalf("Failed to initialize CSINode while waiting for API server to report ok: %v", err)
384: 		}
385: 
386: 		// Backoff parameters tuned to retry over 140 seconds. Will fail and restart the Kubelet
387: 		// after max retry steps.
388: 		initBackoff := wait.Backoff{
389: 			Steps:    6,
390: 			Duration: 30 * time.Millisecond,
391: 			Factor:   8.0,
392: 			Jitter:   0.1,
393: 		}
394: 		err = wait.ExponentialBackoff(initBackoff, func() (bool, error) {
395: 			klog.V(4).Infof("Initializing migrated drivers on CSINode")
396: 			err := nim.InitializeCSINodeWithAnnotation()
397: 			if err != nil {
398: 				kvh.SetKubeletError(fmt.Errorf("failed to initialize CSINode: %v", err))
399: 				klog.Errorf("Failed to initialize CSINode: %v", err)
400: 				return false, nil
401: 			}
402: 
403: 			// Successfully initialized drivers, allow Kubelet to post Ready
404: 			kvh.SetKubeletError(nil)
405: 			return true, nil
406: 		})
407: 		if err != nil {
408: 			// 2 releases after CSIMigration and all CSIMigrationX (where X is a volume plugin)
409: 			// are permanently enabled the apiserver/controllers can assume that the kubelet is
410: 			// using CSI for all Migrated volume plugins. Then all the CSINode initialization
411: 			// code can be dropped from Kubelet.
412: 			// Kill the Kubelet process and allow it to restart to retry initialization
413: 			klog.Fatalf("Failed to initialize CSINode after retrying: %v", err)
414: 		}
415: 	}()
416: 
417: 	if utilfeature.DefaultFeatureGate.Enabled(features.MutableCSINodeAllocatableCount) && csiNodeUpdaterVar == nil {
418: 		if csiDriverInformer != nil {
419: 			var err error
420: 			csiNodeUpdaterVar, err = NewCSINodeUpdater(csiDriverInformer)
421: 			if err != nil {
422: 				klog.ErrorS(err, "Failed to create CSINodeUpdater")
423: 			} else {
424: 				go csiNodeUpdaterVar.Run()
425: 			}
426: 		}
427: 	}
428: 	return nil
429: }
