474: func (p *csiPlugin) NewMounter(
475: 	spec *volume.Spec,
476: 	pod *api.Pod) (volume.Mounter, error) {
477: 
478: 	volSrc, pvSrc, err := getSourceFromSpec(spec)
479: 	if err != nil {
480: 		return nil, err
481: 	}
482: 
483: 	var (
484: 		driverName   string
485: 		volumeHandle string
486: 		readOnly     bool
487: 	)
488: 
489: 	switch {
490: 	case volSrc != nil:
491: 		volumeHandle = makeVolumeHandle(string(pod.UID), spec.Name())
492: 		driverName = volSrc.Driver
493: 		if volSrc.ReadOnly != nil {
494: 			readOnly = *volSrc.ReadOnly
495: 		}
496: 	case pvSrc != nil:
497: 		driverName = pvSrc.Driver
498: 		volumeHandle = pvSrc.VolumeHandle
499: 		readOnly = spec.ReadOnly
500: 	default:
501: 		return nil, errors.New(log("volume source not found in volume.Spec"))
502: 	}
503: 
504: 	volumeLifecycleMode, err := p.getVolumeLifecycleMode(spec)
505: 	if err != nil {
506: 		return nil, err
507: 	}
508: 
509: 	k8s := p.host.GetKubeClient()
510: 	if k8s == nil {
511: 		return nil, errors.New(log("failed to get a kubernetes client"))
512: 	}
513: 
514: 	kvh, ok := p.host.(volume.KubeletVolumeHost)
515: 	if !ok {
516: 		return nil, errors.New(log("cast from VolumeHost to KubeletVolumeHost failed"))
517: 	}
518: 
519: 	mounter := &csiMountMgr{
520: 		plugin:              p,
521: 		k8s:                 k8s,
522: 		spec:                spec,
523: 		pod:                 pod,
524: 		podUID:              pod.UID,
525: 		driverName:          csiDriverName(driverName),
526: 		volumeLifecycleMode: volumeLifecycleMode,
527: 		volumeID:            volumeHandle,
528: 		specVolumeID:        spec.Name(),
529: 		readOnly:            readOnly,
530: 		kubeVolHost:         kvh,
531: 	}
532: 	mounter.csiClientGetter.driverName = csiDriverName(driverName)
533: 
534: 	dir := mounter.GetPath()
535: 	mounter.MetricsProvider = NewMetricsCsi(volumeHandle, dir, csiDriverName(driverName))
536: 	klog.V(4).Info(log("mounter created successfully"))
537: 	return mounter, nil
538: }
