569: func (p *csiPlugin) ConstructVolumeSpec(volumeName, mountPath string) (volume.ReconstructedVolume, error) {
570: 	klog.V(4).Info(log("plugin.ConstructVolumeSpec [pv.Name=%v, path=%v]", volumeName, mountPath))
571: 
572: 	volData, err := loadVolumeData(mountPath, volDataFileName)
573: 	if err != nil {
574: 		return volume.ReconstructedVolume{}, errors.New(log("plugin.ConstructVolumeSpec failed loading volume data using [%s]: %v", mountPath, err))
575: 	}
576: 	klog.V(4).Info(log("plugin.ConstructVolumeSpec extracted [%#v]", volData))
577: 
578: 	var ret volume.ReconstructedVolume
579: 	if utilfeature.DefaultFeatureGate.Enabled(features.SELinuxMountReadWriteOncePod) {
580: 		ret.SELinuxMountContext = volData[volDataKey.seLinuxMountContext]
581: 	}
582: 
583: 	// If mode is VolumeLifecycleEphemeral, use constructVolSourceSpec
584: 	// to construct volume source spec. If mode is VolumeLifecyclePersistent,
585: 	// use constructPVSourceSpec to construct volume construct pv source spec.
586: 	if storage.VolumeLifecycleMode(volData[volDataKey.volumeLifecycleMode]) == storage.VolumeLifecycleEphemeral {
587: 		ret.Spec = p.constructVolSourceSpec(volData[volDataKey.specVolID], volData[volDataKey.driverName])
588: 		return ret, nil
589: 	}
590: 
591: 	ret.Spec = p.constructPVSourceSpec(volData[volDataKey.specVolID], volData[volDataKey.driverName], volData[volDataKey.volHandle])
592: 	return ret, nil
593: }
