729: func (p *csiPlugin) NewBlockVolumeMapper(spec *volume.Spec, podRef *api.Pod) (volume.BlockVolumeMapper, error) {
730: 	pvSource, err := getCSISourceFromSpec(spec)
731: 	if err != nil {
732: 		return nil, err
733: 	}
734: 	readOnly, err := getReadOnlyFromSpec(spec)
735: 	if err != nil {
736: 		return nil, err
737: 	}
738: 
739: 	klog.V(4).Info(log("setting up block mapper for [volume=%v,driver=%v]", pvSource.VolumeHandle, pvSource.Driver))
740: 
741: 	k8s := p.host.GetKubeClient()
742: 	if k8s == nil {
743: 		return nil, errors.New(log("failed to get a kubernetes client"))
744: 	}
745: 
746: 	mapper := &csiBlockMapper{
747: 		k8s:        k8s,
748: 		plugin:     p,
749: 		volumeID:   pvSource.VolumeHandle,
750: 		driverName: csiDriverName(pvSource.Driver),
751: 		readOnly:   readOnly,
752: 		spec:       spec,
753: 		specName:   spec.Name(),
754: 		pod:        podRef,
755: 		podUID:     podRef.UID,
756: 	}
757: 	mapper.csiClientGetter.driverName = csiDriverName(pvSource.Driver)
758: 
759: 	// Save volume info in pod dir
760: 	dataDir := getVolumeDeviceDataDir(spec.Name(), p.host)
761: 
762: 	if err := os.MkdirAll(dataDir, 0750); err != nil {
763: 		return nil, errors.New(log("failed to create data dir %s:  %v", dataDir, err))
764: 	}
765: 	klog.V(4).Info(log("created path successfully [%s]", dataDir))
766: 
767: 	blockPath, err := mapper.GetGlobalMapPath(spec)
768: 	if err != nil {
769: 		return nil, errors.New(log("failed to get device path: %v", err))
770: 	}
771: 
772: 	mapper.MetricsProvider = NewMetricsCsi(pvSource.VolumeHandle, blockPath+"/"+string(podRef.UID), csiDriverName(pvSource.Driver))
773: 
774: 	// persist volume info data for teardown
775: 	node := string(p.host.GetNodeName())
776: 	attachID := getAttachmentName(pvSource.VolumeHandle, pvSource.Driver, node)
777: 	volData := map[string]string{
778: 		volDataKey.specVolID:    spec.Name(),
779: 		volDataKey.volHandle:    pvSource.VolumeHandle,
780: 		volDataKey.driverName:   pvSource.Driver,
781: 		volDataKey.nodeName:     node,
782: 		volDataKey.attachmentID: attachID,
783: 	}
784: 
785: 	err = saveVolumeData(dataDir, volDataFileName, volData)
786: 	defer func() {
787: 		// Only if there was an error and volume operation was considered
788: 		// finished, we should remove the directory.
789: 		if err != nil && volumetypes.IsOperationFinishedError(err) {
790: 			// attempt to cleanup volume mount dir.
791: 			if err = removeMountDir(p, dataDir); err != nil {
792: 				klog.Error(log("attacher.MountDevice failed to remove mount dir after error [%s]: %v", dataDir, err))
793: 			}
794: 		}
795: 	}()
796: 	if err != nil {
797: 		errorMsg := log("csi.NewBlockVolumeMapper failed to save volume info data: %v", err)
798: 		klog.Error(errorMsg)
799: 		return nil, errors.New(errorMsg)
800: 	}
801: 
802: 	return mapper, nil
803: }
