856: // skipAttach looks up CSIDriver object associated with driver name
857: // to determine if driver requires attachment volume operation
858: func (p *csiPlugin) skipAttach(driver string) (bool, error) {
859: 	csiDriver, err := p.getCSIDriver(driver)
860: 	if err != nil {
861: 		if apierrors.IsNotFound(err) {
862: 			// Don't skip attach if CSIDriver does not exist
863: 			return false, nil
864: 		}
865: 		return false, err
866: 	}
867: 	if csiDriver.Spec.AttachRequired != nil && *csiDriver.Spec.AttachRequired == false {
868: 		return true, nil
869: 	}
870: 	return false, nil
871: }
