873: func (p *csiPlugin) getCSIDriver(driver string) (*storage.CSIDriver, error) {
874: 	kletHost, ok := p.host.(volume.KubeletVolumeHost)
875: 	if ok {
876: 		if err := kletHost.WaitForCacheSync(); err != nil {
877: 			return nil, err
878: 		}
879: 	}
880: 
881: 	if p.csiDriverLister == nil {
882: 		return nil, errors.New("CSIDriver lister does not exist")
883: 	}
884: 	csiDriver, err := p.csiDriverLister.Get(driver)
885: 	return csiDriver, err
886: }
