888: // getVolumeLifecycleMode returns the mode for the specified spec: {persistent|ephemeral}.
889: // 1) If mode cannot be determined, it will default to "persistent".
890: // 2) If Mode cannot be resolved to either {persistent | ephemeral}, an error is returned
891: // See https://github.com/kubernetes/enhancements/blob/master/keps/sig-storage/596-csi-inline-volumes/README.md
892: func (p *csiPlugin) getVolumeLifecycleMode(spec *volume.Spec) (storage.VolumeLifecycleMode, error) {
893: 	// 1) if volume.Spec.Volume.CSI != nil -> mode is ephemeral
894: 	// 2) if volume.Spec.PersistentVolume.Spec.CSI != nil -> persistent
895: 	volSrc, _, err := getSourceFromSpec(spec)
896: 	if err != nil {
897: 		return "", err
898: 	}
899: 
900: 	if volSrc != nil {
901: 		return storage.VolumeLifecycleEphemeral, nil
902: 	}
903: 	return storage.VolumeLifecyclePersistent, nil
904: }
