906: func (p *csiPlugin) getPublishContext(client clientset.Interface, handle, driver, nodeName string) (map[string]string, error) {
907: 	skip, err := p.skipAttach(driver)
908: 	if err != nil {
909: 		return nil, err
910: 	}
911: 	if skip {
912: 		return nil, nil
913: 	}
914: 
915: 	attachID := getAttachmentName(handle, driver, nodeName)
916: 
917: 	// search for attachment by VolumeAttachment.Spec.Source.PersistentVolumeName
918: 	attachment, err := client.StorageV1().VolumeAttachments().Get(context.TODO(), attachID, meta.GetOptions{})
919: 	if err != nil {
920: 		return nil, err // This err already has enough context ("VolumeAttachment xyz not found")
921: 	}
922: 
923: 	if attachment == nil {
924: 		err = errors.New("no existing VolumeAttachment found")
925: 		return nil, err
926: 	}
927: 	return attachment.Status.AttachmentMetadata, nil
928: }
