972: // waitForAPIServerForever waits forever to get a CSINode instance as a proxy
973: // for a healthy APIServer
974: func waitForAPIServerForever(client clientset.Interface, nodeName types.NodeName) error {
975: 	var lastErr error
976: 	// Served object is discarded so no risk to have stale object with benefit to
977: 	// reduce the load on APIServer and etcd.
978: 	opts := meta.GetOptions{}
979: 	util.FromApiserverCache(&opts)
980: 	err := wait.PollImmediateInfinite(time.Second, func() (bool, error) {
981: 		// Get a CSINode from API server to make sure 1) kubelet can reach API server
982: 		// and 2) it has enough permissions. Kubelet may have restricted permissions
983: 		// when it's bootstrapping TLS.
984: 		// https://kubernetes.io/docs/reference/access-authn-authz/kubelet-tls-bootstrapping/
985: 		_, lastErr = client.StorageV1().CSINodes().Get(context.TODO(), string(nodeName), opts)
986: 		if lastErr == nil || apierrors.IsNotFound(lastErr) {
987: 			// API server contacted
988: 			return true, nil
989: 		}
990: 		klog.V(2).Infof("Failed to contact API server when waiting for CSINode publishing: %s", lastErr)
991: 		return false, nil
992: 	})
993: 	if err != nil {
994: 		// In theory this is unreachable, but just in case:
995: 		return fmt.Errorf("%v: %v", err, lastErr)
996: 	}
997: 
998: 	return nil
999: }
